// stores/wishlistStore.js
import { create } from 'zustand';
import { persist } from 'zustand/middleware';

export const useWishlistStore = create(
  persist(
    (set, get) => ({
      items: [], // tableau d'IDs de produits

      addToWishlist: (productId) => set((state) => ({
        items: state.items.includes(productId) 
          ? state.items 
          : [...state.items, productId]
      })),

      removeFromWishlist: (productId) => set((state) => ({
        items: state.items.filter(id => id !== productId)
      })),

      toggleWishlist: (productId) => {
        const isFav = get().isFavorite(productId);
        if (isFav) {
          get().removeFromWishlist(productId);
        } else {
          get().addToWishlist(productId);
        }
      },

      isFavorite: (productId) => get().items.includes(productId),

      clearWishlist: () => set({ items: [] }),

      // Synchronisation avec le backend
      syncWithBackend: async (userId, token) => {
        const localItems = get().items;
        try {
          // Récupérer les favoris distants
          const remoteWishlist = await wishlistApi.getWishlist(userId, token);
          // Fusionner (union des deux ensembles)
          const merged = [...new Set([...localItems, ...remoteWishlist])];
          set({ items: merged });
          // Envoyer la fusion au backend
          await wishlistApi.syncWishlist(userId, merged, token);
          return merged;
        } catch (error) {
          console.error('Erreur synchronisation favoris:', error);
        }
      }
    }),
    {
      name: 'wishlist-storage', // clé dans localStorage
      partialize: (state) => ({ items: state.items })
    }
  )
);
