```javascript
// stores/cartStore.js augmenté
import { create } from 'zustand';
import { persist } from 'zustand/middleware';

export const useCartStore = create(
  persist(
    (set, get) => ({
      items: [],
      lastActivity: null, // timestamp du dernier ajout/modification
      notificationShown: false,

      updateLastActivity: () => set({ lastActivity: Date.now() }),

      addToCart: (product) => {
        // ... logique d'ajout
        get().updateLastActivity();
      },

      checkAbandonedCart: () => {
        const { items, lastActivity, notificationShown } = get();
        if (items.length === 0) return false;
        if (notificationShown) return false;

        const TWO_HOURS = 2 * 60 * 60 * 1000;
        const now = Date.now();
        const isAbandoned = lastActivity && (now - lastActivity) > TWO_HOURS;

        if (isAbandoned) {
          set({ notificationShown: true });
          return true;
        }
        return false;
      },

      resetNotification: () => set({ notificationShown: false })
    }),
    { name: 'cart-storage' }
  )
);

// Dans App.jsx (ou Layout principal)
import { useEffect } from 'react';
import { toast } from 'sonner';
import { useCartStore } from './stores/cartStore';

function App() {
  const { items, checkAbandonedCart, resetNotification } = useCartStore();
  const itemCount = items.reduce((sum, i) => sum + i.quantity, 0);

  useEffect(() => {
    const isAbandoned = checkAbandonedCart();
    if (isAbandoned && itemCount > 0) {
      toast.info(`🛒 Vous avez ${itemCount} article(s) dans votre panier !`, {
        duration: 8000,
        position: 'top-center',
        action: {
          label: 'Voir mon panier',
          onClick: () => window.location.href = '/cart'
        }
      });
    }
  }, []);

  // Détection de la fermeture de l'onglet
  useEffect(() => {
    const handleBeforeUnload = (e) => {
      if (itemCount > 0) {
        // Stocker dans sessionStorage pour détecter abandon
        sessionStorage.setItem('abandonedCart', JSON.stringify({
          items: items,
          timestamp: Date.now()
        }));
      }
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [items]);

  return <RouterProvider router={router} />;
}
```

